/**
 * Desktop sandbox handle with enhanced computer use capabilities
 */
export class DesktopSandboxHandle {
  readonly id: string
  readonly streamUrl?: string
  private sandbox: DesktopSandbox
  private ampSessions = new Map<string, AmpSession>()
  private mcpConfigured = false
  private mcpUrl?: string
  private mcpToken?: string

  constructor(sandbox: DesktopSandbox, streamUrl?: string) {
    this.sandbox = sandbox
    this.id = sandbox.id || `desktop-${Date.now()}`
    this.streamUrl = streamUrl
  }

  /**
   * Get VNC stream URL for browser-based desktop viewing
   */
  getStreamUrl(): string | undefined {
    return this.streamUrl
  }

  /**
   * Take a screenshot of the current desktop state
   * Returns Buffer containing PNG image data
   */
  async screenshot(): Promise<Buffer> {
    try {
      const img = await this.sandbox.screenshot()
      return img
    } catch (error: any) {
      console.error('[E2B Desktop] Screenshot error:', error)
      throw error
    }
  }

  /**
   * Take a screenshot and return as base64 (useful for LLM APIs)
   */
  async screenshotBase64(): Promise<string> {
    const buffer = await this.screenshot()
    return buffer.toString('base64')
  }

  // ==================== Mouse Actions ====================

  /**
   * Move mouse to specified coordinates
   */
  async moveMouse(x: number, y: number): Promise<ToolResult> {
    try {
      await this.sandbox.moveMouse(x, y)
      return { success: true, output: `Mouse moved to (${x}, ${y})` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Left click at specified coordinates (or current position)
   */
  async leftClick(x?: number, y?: number, button: 'left' | 'right' | 'middle' = 'left'): Promise<ToolResult> {
    try {
      if (button === 'left') {
        await this.sandbox.leftClick(x, y)
      } else if (button === 'right') {
        await this.sandbox.rightClick(x, y)
      } else if (button === 'middle') {
        await this.sandbox.middleClick(x, y)
      }
      return { success: true, output: `${button} click at (${x ?? 'current'}, ${y ?? 'current'})` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Right click at specified coordinates (or current position)
   */
  async rightClick(x?: number, y?: number): Promise<ToolResult> {
    return this.leftClick(x, y, 'right')
  }

  /**
   * Double click at specified coordinates (or current position)
   */
  async doubleClick(x?: number, y?: number): Promise<ToolResult> {
    try {
      await this.sandbox.doubleClick(x, y)
      return { success: true, output: `Double click at (${x ?? 'current'}, ${y ?? 'current'})` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Drag mouse from start to end coordinates
   */
  async drag(startX: number, startY: number, endX: number, endY: number): Promise<ToolResult> {
    try {
      await this.sandbox.drag([startX, startY], [endX, endY])
      return { success: true, output: `Dragged from (${startX}, ${startY}) to (${endX}, ${endY})` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Scroll up or down
   */
  async scroll(direction: 'up' | 'down' | 'left' | 'right', ticks: number = 1): Promise<ToolResult> {
    try {
      await this.sandbox.scroll(direction, ticks)
      return { success: true, output: `Scrolled ${direction} ${ticks} tick(s)` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  // ==================== Keyboard Actions ====================

  /**
   * Type text (simulates keyboard input)
   */
  async type(text: string): Promise<ToolResult> {
    try {
      await this.sandbox.write(text)
      return { success: true, output: `Typed: ${text.substring(0, 50)}${text.length > 50 ? '...' : ''}` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Press a key or key combination
   */
  async press(key: string | string[]): Promise<ToolResult> {
    try {
      const keys = Array.isArray(key) ? key : [key]
      for (const k of keys) {
        await this.sandbox.press(k)
      }
      return { success: true, output: `Pressed: ${keys.join(' + ')}` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Press key combination (e.g., Ctrl+C, Alt+Tab)
   */
  async hotkey(...keys: string[]): Promise<ToolResult> {
    try {
      await this.sandbox.keyboard.hotkey(keys)
      return { success: true, output: `Hotkey: ${keys.join(' + ')}` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  // ==================== Clipboard Actions ====================

  /**
   * Read clipboard content
   */
  async clipboardRead(): Promise<ToolResult> {
    try {
      const text = await this.sandbox.clipboard.read()
      return { success: true, output: text }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  /**
   * Write to clipboard
   */
  async clipboardWrite(text: string): Promise<ToolResult> {
    try {
      await this.sandbox.clipboard.write(text)
      return { success: true, output: `Clipboard updated (${text.length} chars)` }
    } catch (error: any) {
      return { success: false, output: error.message }
    }
  }

  // ==================== AMP Integration with Sessions ====================

  /**
   * Run AMP (Amp Code) agent in the desktop sandbox
   *
   * Enhanced features:
   * - Session persistence for follow-up tasks
   * - Schema-validated output for reliable pipelines
   * - Custom system prompts via CLAUDE.md
   * - Streaming JSON output for real-time monitoring
   *
   * @see https://e2b.dev/docs/agents/amp
   */
  async runAmpAgent(
    task: string,
    options: {
      streamJson?: boolean
      sessionId?: string
      outputSchema?: any
      outputSchemaPath?: string
      systemPrompt?: string
      onEvent?: (event: any) => void
      timeout?: number
    } = {}
  ): Promise<{
    success: boolean
    output: string
    sessionId?: string
    events?: any[]
  }> {
    const events: any[] = []
    let sessionId = options.sessionId

    try {
      // Build AMP command with all options
      const ampCommandParts = [
        'amp',
        '--dangerously-skip-permissions',
      ]

      // Add session ID for conversation persistence
      if (options.sessionId) {
        ampCommandParts.push(`--session-id ${options.sessionId}`)
      }

      // Add output format
      ampCommandParts.push(options.streamJson ? '--output-format stream-json' : '--output-format json')

      // Add schema validation for reliable pipelines
      if (options.outputSchema || options.outputSchemaPath) {
        const schemaPath = options.outputSchemaPath || '/tmp/output-schema.json'
        ampCommandParts.push(`--output-schema ${schemaPath}`)

        // Write schema if provided inline
        if (options.outputSchema && !options.outputSchemaPath) {
          await this.sandbox.files.write(schemaPath, JSON.stringify(options.outputSchema))
        }
      }

      // Add custom system prompt via CLAUDE.md
      if (options.systemPrompt) {
        await this.sandbox.files.write('/home/user/CLAUDE.md', options.systemPrompt)
        ampCommandParts.push(`--system-prompt "${options.systemPrompt}"`)
      }

      // Add task
      ampCommandParts.push('-x', `"${task}"`)

      const ampCommand = ampCommandParts.filter(Boolean).join(' ')

      const result = await this.sandbox.commands.run(ampCommand, {
        timeout: options.timeout || 300000,
        onStdout: options.streamJson ? (data: string) => {
          // Parse streaming JSON events
          for (const line of data.split('\n').filter(Boolean)) {
            try {
              const event = JSON.parse(line)
              events.push(event)
              options.onEvent?.(event)

              // Track session ID from result events for continuation
              if (event.type === 'result' && event.session_id) {
                sessionId = event.session_id
                this.ampSessions.set(sessionId, {
                  sessionId,
                  createdAt: Date.now(),
                  lastUsed: Date.now(),
                  task,
                })
              }
            } catch {
              // Not JSON, ignore
            }
          }
        } : undefined,
      })

      return {
        success: result.exitCode === 0,
        output: result.stdout || result.stderr || '',
        sessionId,
        events: options.streamJson ? events : undefined,
      }
    } catch (error: any) {
      return {
        success: false,
        output: error.message,
        sessionId,
        events: events.length > 0 ? events : undefined,
      }
    }
  }

  /**
   * List AMP sessions for conversation persistence
   */
  listAmpSessions(): AmpSession[] {
    return Array.from(this.ampSessions.values())
  }

  /**
   * Get MCP gateway URL
   *
   * @see https://e2b.dev/docs/mcp
   */
  async getMcpUrl(): Promise<string> {
    if (this.mcpUrl) {
      return this.mcpUrl
    }

    // Get MCP gateway URL from sandbox
    this.mcpUrl = `https://mcp.${this.id}.e2b.dev`
    return this.mcpUrl
  }

  /**
   * Get MCP auth token
   */
  async getMcpToken(): Promise<string> {
    if (this.mcpToken) {
      return this.mcpToken
    }

    // Get MCP auth token
    const result = await this.sandbox.commands.run('e2b mcp token')
    this.mcpToken = result.stdout.trim()
    return this.mcpToken
  }

  /**
   * Setup MCP tools from Docker MCP Catalog
   *
   * Provides access to 200+ tools from the Docker MCP Catalog
   *
   * @see https://hub.docker.com/mcp
   */
  async setupMCP(config: MCPConfig): Promise<{ success: boolean; error?: string }> {
    try {
      const mcpUrl = await this.getMcpUrl()
      const mcpToken = await this.getMcpToken()

      // Add each MCP tool
      for (const [toolName, toolConfig] of Object.entries(config)) {
        const envVars = Object.entries(toolConfig)
          .map(([k, v]) => `${k.toUpperCase()}=${v}`)
          .join(' ')

        await this.sandbox.commands.run(
          `claude mcp add --transport http ${toolName} ${mcpUrl} ` +
          `--header "Authorization: Bearer ${mcpToken}" ` +
          `--env "${envVars}"`
        )
      }

      this.mcpConfigured = true
      return { success: true }
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  }

  /**
   * Check if MCP is configured
   */
  isMCPConfigured(): boolean {
    return this.mcpConfigured
  }

  // ==================== Stats & Lifecycle ====================

  /**
   * Check if desktop sandbox is still alive
   */
  isAlive(): boolean {
    // Sandbox is considered alive if it has an id and hasn't been killed
    return !!this.id && !!this.sandbox
  }

  /**
   * Get desktop statistics for monitoring
   */
  getStats(): DesktopStats {
    return {
      id: this.id,
      uptime: Date.now() - (this.sandbox?.createdAt || Date.now()),
      actionCount: 0, // Could be tracked internally if needed
      lastActionAt: undefined,
      resolution: DESKTOP_DEFAULT_RESOLUTION,
      streamUrl: this.streamUrl,
      mcpConfigured: this.mcpConfigured,
      activeSessions: this.ampSessions.size,
    }
  }

  /**
   * Kill the desktop sandbox
   */
  async kill(): Promise<void> {
    try {
      await this.sandbox.kill()
      console.log('[E2B Desktop] Sandbox killed')
    } catch (error: any) {
      console.error('[E2B Desktop] Kill error:', error)
    }
  }

  /**
   * Get sandbox info
   */
  async getInfo(): Promise<{
    id: string
    template: string
    resolution: [number, number]
    timeout: number
    streamUrl?: string
    mcpConfigured: boolean
    activeSessions: number
  }> {
    return {
      id: this.id,
      template: 'desktop',
      resolution: DESKTOP_DEFAULT_RESOLUTION,
      timeout: DESKTOP_DEFAULT_TIMEOUT,
      streamUrl: this.streamUrl,
      mcpConfigured: this.mcpConfigured,
      activeSessions: this.ampSessions.size,
    }
  }
}

/**
 * E2B Desktop Provider
 * Creates and manages desktop sandbox environments
 */
export class E2BDesktopProvider {
  readonly name = 'e2b-desktop'
  private apiKey?: string

  constructor(apiKey?: string) {
    this.apiKey = apiKey || process.env.E2B_API_KEY

    if (!this.apiKey) {
      console.warn('[E2BDesktopProvider] E2B_API_KEY not set')
    }
  }

  /**
   * Create a new desktop sandbox with VNC streaming
   *
   * @param config - Configuration options
   * @param config.template - Desktop template ID (default: 'desktop')
   * @param config.resolution - Screen resolution [width, height] (default: [1920, 1080])
   * @param config.dpi - Screen DPI (default: 96)
   * @param config.timeoutMs - Session timeout in milliseconds (default: 300000)
   * @param config.startStreaming - Start VNC streaming (default: true)
   */
  async createDesktop(config: {
    template?: string
    resolution?: [number, number]
    dpi?: number
    timeoutMs?: number
    startStreaming?: boolean
  } = {}): Promise<DesktopSandboxHandle> {
    if (!this.apiKey) {
      throw new Error('E2B_API_KEY is not configured')
    }

    try {
      // Dynamic import to avoid requiring @e2b/desktop when not used
      const { Desktop } = await import('@e2b/desktop')

      const sandbox = await Desktop.create({
        template: config.template || 'desktop',
        timeoutMs: config.timeoutMs || DESKTOP_DEFAULT_TIMEOUT,
        resolution: config.resolution || DESKTOP_DEFAULT_RESOLUTION,
        dpi: config.dpi || 96,
      })

      let streamUrl: string | undefined

      // Start VNC streaming if requested
      if (config.startStreaming !== false) {
        streamUrl = await sandbox.screen.getStreamUrl()
        console.log(`[E2BDesktopProvider] VNC stream available at: ${streamUrl}`)
      }

      // Record usage
      quotaManager.recordUsage('e2b', 1)

      console.log(`[E2BDesktopProvider] Created desktop sandbox ${sandbox.id}`)

      return new DesktopSandboxHandle(sandbox, streamUrl)
    } catch (error: any) {
      console.error('[E2BDesktopProvider] Failed to create desktop:', error)
      throw new Error(`Failed to create E2B Desktop: ${error.message}`)
    }
  }
}

// Export singleton instance
export const e2bDesktopProvider = new E2BDesktopProvider()

/**
 * Desktop session manager for tracking active desktops
 */
export const desktopSessionManager = {
  sessions: new Map<string, DesktopSandboxHandle>(),

  async createSession(
    sessionId: string,
    config?: {
      template?: string
      resolution?: [number, number]
      dpi?: number
      timeoutMs?: number
      startStreaming?: boolean
      autoCleanup?: boolean
    }
  ): Promise<DesktopSandboxHandle> {
    const desktop = await e2bDesktopProvider.createDesktop(config)
    this.sessions.set(sessionId, desktop)
    return desktop
  },

  getSession(sessionId: string): DesktopSandboxHandle | undefined {
    return this.sessions.get(sessionId)
  },

  async destroySession(sessionId: string): Promise<void> {
    const desktop = this.sessions.get(sessionId)
    if (desktop) {
      await desktop.kill()
      this.sessions.delete(sessionId)
    }
  },

  getActiveSessions(): string[] {
    return Array.from(this.sessions.keys())
  },
}

/**
 * Execute desktop command via API route helper
 */
export async function executeDesktopCommand(
  sessionId: string,
  action: 'screenshot' | 'click' | 'type' | 'keypress' | 'move' | 'drag' | 'clipboard_read' | 'clipboard_write',
  params: Record<string, any>
): Promise<ToolResult> {
  const desktop = desktopSessionManager.getSession(sessionId)

  if (!desktop) {
    return {
      success: false,
      output: `Desktop session not found: ${sessionId}`,
    }
  }

  try {
    switch (action) {
      case 'screenshot': {
        const screenshot = await desktop.screenshot()
        return {
          success: true,
          output: `Screenshot captured (${screenshot.length} bytes)`,
          binary: screenshot,
        }
      }

      case 'click': {
        const { x, y, button = 'left' } = params
        return await desktop.leftClick(x, y, button)
      }

      case 'type': {
        return await desktop.type(params.text || '')
      }

      case 'keypress': {
        return await desktop.press(params.key || params.keys || [])
      }

      case 'move': {
        return await desktop.moveMouse(params.x || 0, params.y || 0)
      }

      case 'drag': {
        return await desktop.drag(params.startX || 0, params.startY || 0, params.endX || 0, params.endY || 0)
      }

      case 'clipboard_read': {
        return await desktop.clipboardRead()
      }

      case 'clipboard_write': {
        return await desktop.clipboardWrite(params.text || '')
      }

      default:
        return {
          success: false,
          output: `Unknown desktop action: ${action}`,
        }
    }
  } catch (error: any) {
    return {
      success: false,
      output: `Desktop action failed: ${error.message}`,
    }
  }
}

import { Daytona } from '@daytonaio/sdk'
import { resolve, relative } from 'node:path'
import type { ToolResult, PreviewInfo } from '../types'
import type {
  SandboxProvider,
  SandboxHandle,
  SandboxCreateConfig,
  PtyHandle,
  PtyOptions,
  PtyConnectOptions,
} from './sandbox-provider'
import { ComputerUseService, createComputerUseService } from './daytona-computer-use-service'
import { LSPService, createLSPService, type LSPLanguageId } from './daytona-lsp-service'
import { ObjectStorageService, createObjectStorageService } from './daytona-object-storage-service'

const WORKSPACE_DIR = '/home/daytona/workspace'
const MAX_COMMAND_TIMEOUT = 120

// Persistent cache configuration
const USE_PERSISTENT_CACHE = process.env.SANDBOX_PERSISTENT_CACHE === 'true'
const CACHE_VOLUME_NAME = process.env.SANDBOX_CACHE_VOLUME_NAME || 'global-package-cache'
const CACHE_SIZE = process.env.SANDBOX_CACHE_SIZE || '2GB'

export class DaytonaProvider implements SandboxProvider {
  readonly name = 'daytona'
  private client: Daytona

  constructor() {
    this.client = new Daytona({
      apiKey: process.env.DAYTONA_API_KEY!,
    })
  }

  async createSandbox(config: SandboxCreateConfig): Promise<SandboxHandle> {
    // Map language to Docker image
    // Using official Docker Hub images - Daytona accepts any valid Docker image reference
    // See: https://www.daytona.io/docs/en/getting-started.md#create-a-sandbox
    const imageMap: Record<string, string> = {
      // TypeScript/JavaScript - Node.js official images
      'typescript': 'node:20-slim',
      'javascript': 'node:20-slim',
      'node': 'node:20-slim',
      'nodejs': 'node:20-slim',

      // Python official images
      'python': 'python:3.11-slim',
      'python3': 'python:3.11-slim',
      'py': 'python:3.11-slim',

      // Go official images
      'go': 'golang:1.21',
      'golang': 'golang:1.21',

      // Rust official images
      'rust': 'rust:1.74',
      'rustlang': 'rust:1.74',

      // Java official images
      'java': 'eclipse-temurin:17-jre-alpine',
      'jdk': 'eclipse-temurin:17-jre-alpine',
      'jvm': 'eclipse-temurin:17-jre-alpine',

      // C/C++ official images
      'c': 'gcc:13',
      'cpp': 'gcc:13',
      'c++': 'gcc:13',
      'gcc': 'gcc:13',

      // Ruby official images
      'ruby': 'ruby:3.2-slim',
      'rb': 'ruby:3.2-slim',

      // PHP official images
      'php': 'php:8.2-cli',

      // .NET official images
      'csharp': 'mcr.microsoft.com/dotnet/sdk:8.0',
      'dotnet': 'mcr.microsoft.com/dotnet/sdk:8.0',
      '.net': 'mcr.microsoft.com/dotnet/sdk:8.0',

      // General purpose / multi-language
      'ubuntu': 'ubuntu:22.04',
      'debian': 'debian:bookworm-slim',
      'alpine': 'alpine:3.19',
      'bash': 'ubuntu:22.04',
      'shell': 'ubuntu:22.04',

      // Daytona official images (if available)
      'daytona-base': 'daytonaio/sandbox:latest',
    };
    const image = imageMap[config.language ?? 'typescript'] || 'node:20-slim';

    // Build sandbox creation params
    const createParams: any = {
      image: image,
      autoStopInterval: config.autoStopInterval ?? 60,
      resources: config.resources ?? { cpu: 2, memory: 4 },
      envVars: {
        TERM: 'xterm-256color',
        LANG: 'en_US.UTF-8',
        ...config.envVars,
      },
      labels: config.labels,
    }

    // Add persistent cache volume if enabled
    if (USE_PERSISTENT_CACHE) {
      createParams.volumes = [
        {
          volumeId: CACHE_VOLUME_NAME,
          mountPath: '/opt/cache',
          readOnly: false,
        }
      ]
      createParams.envVars.SANDBOX_CACHE_ENABLED = 'true'
    }

    const sandbox = await this.client.create(createParams)

    await sandbox.process.executeCommand(`mkdir -p ${WORKSPACE_DIR}`)
    return new DaytonaSandboxHandle(sandbox, this.client)
  }

  async getSandbox(sandboxId: string): Promise<SandboxHandle> {
    const sandbox = await this.client.get(sandboxId)
    return new DaytonaSandboxHandle(sandbox, this.client)
  }

  async destroySandbox(sandboxId: string): Promise<void> {
    const sandbox = await this.client.get(sandboxId)
    await sandbox.delete()
  }
}

import { SandboxSecurityManager } from '../security-manager'

class DaytonaSandboxHandle implements SandboxHandle {
  readonly id: string
  readonly workspaceDir = '/home/daytona/workspace'
  private sandbox: any
  private client: Daytona
  private computerUseService?: ComputerUseService
  private lspService?: LSPService
  private objectStorageService?: ObjectStorageService

  constructor(sandbox: any, client: Daytona) {
    this.sandbox = sandbox
    this.id = sandbox.id
    this.client = client
  }

  /**
   * Get Computer Use Service for this sandbox
   * Requires DAYTONA_API_KEY environment variable
   */
  getComputerUseService(): ComputerUseService | null {
    const apiKey = process.env.DAYTONA_API_KEY
    if (!apiKey) {
      console.warn('[Daytona] DAYTONA_API_KEY not set, Computer Use Service unavailable')
      return null
    }

    if (!this.computerUseService) {
      this.computerUseService = createComputerUseService(this.id, apiKey)
    }

    return this.computerUseService
  }

  /**
   * Get LSP Service for code intelligence
   * Supports TypeScript, Python, Go, Rust, and more
   */
  getLSPService(): LSPService | null {
    const apiKey = process.env.DAYTONA_API_KEY
    if (!apiKey) {
      console.warn('[Daytona] DAYTONA_API_KEY not set, LSP Service unavailable')
      return null
    }

    if (!this.lspService) {
      this.lspService = createLSPService(this.id, apiKey)
    }

    return this.lspService
  }

  /**
   * Get Object Storage Service for large file persistence
   */
  getObjectStorageService(): ObjectStorageService | null {
    const apiKey = process.env.DAYTONA_API_KEY
    if (!apiKey) {
      console.warn('[Daytona] DAYTONA_API_KEY not set, Object Storage unavailable')
      return null
    }

    if (!this.objectStorageService) {
      this.objectStorageService = createObjectStorageService(this.id, apiKey)
    }

    return this.objectStorageService
  }

  /**
   * Start screen recording
   * @see https://www.daytona.io/docs/en/computer-use.md#start-recording
   */
  async startRecording(options?: ScreenRecordingRequest): Promise<ToolResult> {
    const service = this.getComputerUseService()
    if (!service) throw new Error('Computer Use Service not available')
    return service.startRecording(options)
  }

  /**
   * Stop screen recording
   */
  async stopRecording(recordingId: string): Promise<ToolResult> {
    const service = this.getComputerUseService()
    if (!service) throw new Error('Computer Use Service not available')
    return service.stopRecording(recordingId)
  }

  /**
   * Take regional screenshot
   */
  async takeRegionScreenshot(x: number, y: number, width: number, height: number): Promise<ToolResult> {
    const service = this.getComputerUseService()
    if (!service) throw new Error('Computer Use Service not available')
    return service.takeRegion({ x, y, width, height })
  }

  async executeCommand(command: string, cwd?: string, timeout?: number): Promise<ToolResult> {
    try {
      // ✅ ENHANCED: Use combined validation and sanitization
      const sanitized = SandboxSecurityManager.validateAndSanitizeCommand(command)

      const response = await this.sandbox.process.executeCommand(
        sanitized,
        cwd ?? this.workspaceDir,
        undefined,
        timeout ?? MAX_COMMAND_TIMEOUT,
      )

      return {
        success: response.exitCode === 0,
        output: response.result,
        exitCode: response.exitCode,
      }
    } catch (error: any) {
      // Security exceptions should be logged but not expose details
      if (error.message?.includes('Security Exception')) {
        console.warn('[Daytona] Security validation failed:', error.message)
        return {
          success: false,
          output: 'Security validation failed',
        }
      }

      return {
        success: false,
        output: error.message || 'Command execution failed',
        exitCode: -1,
      }
    }
  }

  async writeFile(filePath: string, content: string): Promise<ToolResult> {
    try {
      // ✅ ENHANCED: Use combined validation for path and content
      const { resolvedPath, validatedContent } = SandboxSecurityManager.validateWriteFile(
        filePath,
        content,
        this.workspaceDir
      )

      const dir = resolvedPath.substring(0, resolvedPath.lastIndexOf('/'))
      if (dir) {
        await this.sandbox.fs.createFolder(dir, '755')
      }
      await this.sandbox.fs.uploadFile(Buffer.from(validatedContent, 'utf-8'), resolvedPath)

      return {
        success: true,
        output: `File written: ${resolvedPath}`
      }
    } catch (error: any) {
      // Security exceptions should be logged but not expose details
      if (error.message?.includes('Security Exception')) {
        console.warn('[Daytona] Security validation failed:', error.message)
        return {
          success: false,
          output: 'Security validation failed',
        }
      }

      return {
        success: false,
        output: error.message || 'Failed to write file',
      }
    }
  }

  async readFile(filePath: string): Promise<ToolResult> {
    try {
      // ✅ ENHANCED: Validate path before reading
      const resolved = SandboxSecurityManager.resolvePath(this.workspaceDir, filePath)
      const buffer = await this.sandbox.fs.downloadFile(resolved)
      return {
        success: true,
        output: buffer.toString('utf-8')
      }
    } catch (error: any) {
      // Security exceptions should be logged but not expose details
      if (error.message?.includes('Security Exception')) {
        console.warn('[Daytona] Security validation failed:', error.message)
        return {
          success: false,
          output: 'Security validation failed',
        }
      }

      return {
        success: false,
        output: error.message || 'Failed to read file',
      }
    }
  }

  async listDirectory(dirPath: string): Promise<ToolResult> {
    try {
      // ✅ ENHANCED: Validate path before listing
      const resolved = SandboxSecurityManager.resolvePath(this.workspaceDir, dirPath)
      const files = await this.sandbox.fs.listFiles(resolved)
      const listing = files.map((f: any) => `${f.isDir ? 'd' : '-'} ${f.name}`).join('\n')
      return {
        success: true,
        output: listing || '(empty directory)'
      }
    } catch (error: any) {
      // Security exceptions should be logged but not expose details
      if (error.message?.includes('Security Exception')) {
        console.warn('[Daytona] Security validation failed:', error.message)
        return {
          success: false,
          output: 'Security validation failed',
        }
      }

      return {
        success: false,
        output: error.message || 'Failed to list directory',
      }
    }
  }

  async getPreviewLink(port: number): Promise<PreviewInfo> {
    const preview = await this.sandbox.getPreviewLink(port)
    return { port, url: preview.url, token: preview.token }
  }

  async createPty(options: PtyOptions): Promise<PtyHandle> {
    const ptyHandle = await this.sandbox.process.createPty({
      id: options.id,
      cwd: options.cwd ?? this.workspaceDir,
      envs: options.envs ?? { TERM: 'xterm-256color' },
      cols: options.cols ?? 120,
      rows: options.rows ?? 30,
      onData: options.onData,
    })

    return new DaytonaPtyHandle(options.id, ptyHandle)
  }

  async connectPty(sessionId: string, options: PtyConnectOptions): Promise<PtyHandle> {
    const ptyHandle = await this.sandbox.process.connectPty(sessionId, {
      onData: options.onData,
    })
    return new DaytonaPtyHandle(sessionId, ptyHandle)
  }

  async killPty(sessionId: string): Promise<void> {
    const ptyHandle = await this.sandbox.process.getPty(sessionId)
    if (ptyHandle) {
      await ptyHandle.kill()
    }
  }

  async resizePty(sessionId: string, cols: number, rows: number): Promise<void> {
    const ptyHandle = await this.sandbox.process.getPty(sessionId)
    if (ptyHandle) {
      await ptyHandle.resize(cols, rows)
    }
  }
}

class DaytonaPtyHandle implements PtyHandle {
  readonly sessionId: string
  private handle: any

  constructor(sessionId: string, handle: any) {
    this.sessionId = sessionId
    this.handle = handle
  }

  async sendInput(data: string): Promise<void> {
    await this.handle.sendInput(data)
  }

  async resize(cols: number, rows: number): Promise<void> {
    await this.handle.resize(cols, rows)
  }

  async waitForConnection(): Promise<void> {
    await this.handle.waitForConnection()
  }

  async wait(): Promise<{ exitCode: number }> {
    await this.handle.wait()
    return { exitCode: this.handle.exitCode || 0 }
  }

  async disconnect(): Promise<void> {
    await this.handle.disconnect()
  }

  async kill(): Promise<void> {
    await this.handle.kill()
  }
}

/**
 * Daytona Computer Use Service
 *
 * Provides computer use capabilities for AI agents to interact with
 * graphical desktop environments via Daytona's Computer Use API.
 *
 * Features:
 * - Mouse operations (click, move, drag, scroll, get position)
 * - Keyboard operations (type, press, hotkey)
 * - Screenshot operations (full screen, region, compressed)
 * - Screen recording (start, stop, list, download)
 * - Display operations (get info, get windows)
 *
 * @see https://www.daytona.io/docs/en/computer-use.md
 */

import type { ToolResult } from '../types'

// Computer Use API types
export interface MouseClickRequest {
  x?: number
  y?: number
  button?: 'left' | 'right' | 'middle'
}

export interface MouseMoveRequest {
  x: number
  y: number
}

export interface MouseDragRequest {
  startX: number
  startY: number
  endX: number
  endY: number
}

export interface MouseScrollRequest {
  direction: 'up' | 'down' | 'left' | 'right'
  ticks?: number
}

export interface KeyboardTypeRequest {
  text: string
  delay?: number
}

export interface KeyboardPressRequest {
  keys: string | string[]
}

export interface ScreenshotRequest {
  region?: {
    x: number
    y: number
    width: number
    height: number
  }
  quality?: number
}

export interface ScreenRecordingRequest {
  path?: string
  duration?: number
}

export interface ComputerUseStatus {
  active: boolean
  processId?: string
  display?: number
  errorMessage?: string
}

/**
 * Daytona Computer Use Service
 */
export class ComputerUseService {
  private sandboxId: string
  private apiBaseUrl: string
  private apiKey: string

  constructor(sandboxId: string, apiKey: string, apiBaseUrl: string = 'https://app.daytona.io/api') {
    this.sandboxId = sandboxId
    this.apiKey = apiKey
    this.apiBaseUrl = apiBaseUrl
  }

  /**
   * Get computer use status
   */
  async getStatus(): Promise<ComputerUseStatus> {
    const response = await fetch(
      `${this.apiBaseUrl}/computer-use/${this.sandboxId}/status`,
      {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${this.apiKey}`,
          'Content-Type': 'application/json',
        },
      }
    )

    if (!response.ok) {
      throw new Error(`Failed to get status: ${response.statusText}`)
    }

    return response.json()
  }

  // ==================== Mouse Operations ====================

  /**
   * Click mouse at specified coordinates
   */
  async click(options: MouseClickRequest): Promise<ToolResult> {
    try {
      const response = await fetch(
        `${this.apiBaseUrl}/computer-use/${this.sandboxId}/mouse/click`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(options),
        }
      )

      if (!response.ok) {
        throw new Error(`Click failed: ${response.statusText}`)
      }

      const coords = options.x !== undefined && options.y !== undefined
        ? `(${options.x}, ${options.y})`
        : 'current position'

      return {
        success: true,
        output: `Clicked ${options.button || 'left'} button at ${coords}`,
      }
    } catch (error: any) {
      return {
        success: false,
        output: `Click failed: ${error.message}`,
      }
    }
  }

  /**
   * Move mouse to specified coordinates
   */
  async move(options: MouseMoveRequest): Promise<ToolResult> {
    try {
      const response = await fetch(
        `${this.apiBaseUrl}/computer-use/${this.sandboxId}/mouse/move`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(options),
        }
      )

      if (!response.ok) {
        throw new Error(`Move failed: ${response.statusText}`)
      }

      return {
        success: true,
        output: `Mouse moved to (${options.x}, ${options.y})`,
      }
    } catch (error: any) {
      return {
        success: false,
        output: `Move failed: ${error.message}`,
      }
    }
  }

  /**
   * Drag mouse from start to end coordinates
   */
  async drag(options: MouseDragRequest): Promise<ToolResult> {
    try {
      const response = await fetch(
        `${this.apiBaseUrl}/computer-use/${this.sandboxId}/mouse/drag`,
        {
          method: 'POST',
          headers: {
            'Authorization': `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
          body: JSON.stringify(options),
        }
      )

      if (!response.ok) {
        throw new Error(`Drag failed: ${response.statusText}`)
      }

      return {
        success: true,
        output: `Dragged from (${options.startX}, ${options.startY}) to (${options.endX}, ${options.endY})`,
      }
    } catch (error: any) {
      return {
        success: false,
        output: `Drag failed: ${error.message}`,
      }
    }
  }

  /**
   * Scroll in specified direction
