      }
    } catch (error: any) {
      return {
        success: false,
        output: `Scroll failed: ${error.message}`,
      }
    }
  }

  /**
   * Get current mouse position
   */
  async getPosition(): Promise<ToolResult> {
    try {
      const response = await fetch(
        `${this.apiBaseUrl}/computer-use/${this.sandboxId}/mouse/position`,
        {
          method: 'GET',
