      }
    } catch (error: any) {
      return {
        success: false,
        output: `Get position failed: ${error.message}`,
      }
    }
  }

  // ==================== Keyboard Operations ====================

  /**
   * Type text
   */
  async type(options: KeyboardTypeRequest): Promise<ToolResult> {
    try {
      const response = await fetch(
        `${this.apiBaseUrl}/computer-use/${this.sandboxId}/keyboard/type`,
