      callback({
        port: portInfo.port,
        host: this.client.hosts.getUrl(portInfo.port),
      })
    })
    return () => listener.dispose()
  }

  onPortClose(callback: (port: number) => void): () => void {
    const listener = this.client.ports.onDidPortClose(callback)
    return () => listener.dispose()
  }

